const https = require('https');

const NOTION_TOKEN = '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';
const NOTION_VERSION = '2022-06-28';

const DBS = {
  utenti:'7e2c3df4-dfb8-4978-adb3-ad83d6d3846b',
  orders:'70deebe9-b8bb-4f0b-b37c-71a3600077b8',
  waitlist:'70aef09d-be42-4574-8e69-dfeb942fa795',
  eventi:'a9fe4ef2-8705-4baf-a6c8-a1e745b65989',
  corsi:'fde954a0-256e-4400-bc19-8abc1bc7c5da',
  fatture:'4a5e516f-2523-46ad-b8c4-dece2b4ec768',
  conti:'7959f2b3-0242-48b0-b37d-64eb78d4946f',
  dipendenti:'dd5c048b-faac-43ae-971f-708877039a0e',
  magazzino:'6d0cbb5a-63ac-43c6-b946-21bb50507f5d',
  documenti:'77d6388b-1335-4e1b-8fe5-8fc34fbe8f84',
  campagne:'a4db1e9a-e548-4de1-80eb-10f36953d01f'
};

// Helper: HTTPS request wrapper (promisified)
function notionReq(method, path, payload) {
  return new Promise((resolve, reject) => {
    const data = payload ? JSON.stringify(payload) : null;
    const opts = {
      hostname: 'api.notion.com',
      path: '/v1' + path,
      method: method,
      headers: {
        'Authorization': 'Bearer ' + NOTION_TOKEN,
        'Notion-Version': NOTION_VERSION,
        'Content-Type': 'application/json'
      }
    };
    if (data) opts.headers['Content-Length'] = Buffer.byteLength(data);
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(body);
          if (res.statusCode >= 400) reject(new Error('Notion ' + res.statusCode + ': ' + (parsed.message || body)));
          else resolve(parsed);
        } catch { reject(new Error('Invalid JSON: ' + body.substring(0, 200))); }
      });
    });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(); reject(new Error('Timeout')); });
    if (data) req.write(data);
    req.end();
  });
}

function extractProps(page) {
  const props = page.properties || {};
  const o = { id: page.id, created: page.created_time, updated: page.last_edited_time };
  for (const [k, p] of Object.entries(props)) {
    switch (p.type) {
      case 'title':        o[k] = (p.title||[]).map(t=>t.plain_text).join(''); break;
      case 'rich_text':    o[k] = (p.rich_text||[]).map(t=>t.plain_text).join(''); break;
      case 'number':       o[k] = p.number; break;
      case 'select':       o[k] = p.select?p.select.name:null; break;
      case 'multi_select': o[k] = (p.multi_select||[]).map(s=>s.name); break;
      case 'date':         o[k] = p.date?p.date.start:null; break;
      case 'checkbox':     o[k] = p.checkbox||false; break;
      case 'email':        o[k] = p.email||''; break;
      case 'phone_number': o[k] = p.phone_number||''; break;
      case 'url':          o[k] = p.url||''; break;
      case 'status':       o[k] = p.status?p.status.name:null; break;
      case 'formula':      o[k] = p.formula?(p.formula.string||p.formula.number):null; break;
      case 'relation':     o[k] = (p.relation||[]).map(r=>r.id); break;
      case 'people':       o[k] = (p.people||[]).map(x=>x.name||x.id); break;
      default:             o[k] = null;
    }
  }
  return o;
}

function buildProps(data) {
  const props = {};
  for (const [k, v] of Object.entries(data)) {
    if (typeof v === 'string') {
      if (['Nome','Name','Titolo','Title','nome','name'].includes(k)) props[k] = { title: [{ text: { content: v } }] };
      else if (k.toLowerCase().includes('email')) props[k] = { email: v };
      else if (k.toLowerCase().includes('url')||k.toLowerCase().includes('link')) props[k] = { url: v };
      else if (k.toLowerCase().includes('phone')||k.toLowerCase().includes('telefono')) props[k] = { phone_number: v };
      else props[k] = { rich_text: [{ text: { content: v } }] };
    } else if (typeof v === 'number') props[k] = { number: v };
    else if (typeof v === 'boolean') props[k] = { checkbox: v };
    else if (v && typeof v === 'object' && v.start) props[k] = { date: { start: v.start, end: v.end||null } };
  }
  return props;
}

async function qCount(id) {
  try { const d = await notionReq('POST','/databases/'+id+'/query',{page_size:100}); return (d.results||[]).length; }
  catch { return 0; }
}

const body = $input.first().json.body;
const action = body.action || 'unknown';
const dbId = body.dbId || '';
let result = { success: false, action };

try {
  if (action === 'list') {
    const pl = { page_size: body.pageSize||100, sorts:[{timestamp:'created_time',direction:'descending'}] };
    if (body.filters && Object.keys(body.filters).length > 0) {
      const e = Object.entries(body.filters);
      pl.filter = e.length===1 ? {property:e[0][0],rich_text:{contains:e[0][1]}} : {and:e.map(([p,v])=>({property:p,rich_text:{contains:v}}))};
    }
    const d = await notionReq('POST','/databases/'+dbId+'/query',pl);
    const items = (d.results||[]).map(extractProps);
    result = { items, total:items.length, page:body.page||1, pageSize:body.pageSize||100, has_more:d.has_more||false };

  } else if (action === 'get') {
    const page = await notionReq('GET','/pages/'+body.id);
    result = { item: extractProps(page) };

  } else if (action === 'create') {
    const page = await notionReq('POST','/pages',{parent:{database_id:dbId},properties:buildProps(body.data||{})});
    result = { item:{id:page.id}, success:true };

  } else if (action === 'update') {
    await notionReq('PATCH','/pages/'+body.id,{properties:buildProps(body.data||{})});
    result = { success:true, id:body.id };

  } else if (action === 'delete') {
    await notionReq('PATCH','/pages/'+body.id,{archived:true});
    result = { success:true, archived:true };

  } else if (action === 'search') {
    const q = body.query||'';
    const d = await notionReq('POST','/databases/'+dbId+'/query',{
      filter:{or:[{property:'Nome',rich_text:{contains:q}},{property:'Name',rich_text:{contains:q}},{property:'Email',rich_text:{contains:q}},{property:'Titolo',rich_text:{contains:q}}]},
      page_size:50
    });
    result = { items:(d.results||[]).map(extractProps), total:(d.results||[]).length };

  } else if (action === 'aggregate') {
    const d = await notionReq('POST','/databases/'+dbId+'/query',{page_size:100});
    const arr = d.results||[];
    const op = body.operation||'count';
    if (op==='count') result = {result:arr.length,operation:'count'};
    else {
      let sum=0,cnt=0;
      for (const pg of arr) { const pr=pg.properties&&pg.properties[body.field]; if(pr&&pr.type==='number'&&pr.number!==null){sum+=pr.number;cnt++;} }
      result = op==='sum'?{result:sum,operation:'sum'}:{result:cnt>0?sum/cnt:0,operation:'avg'};
    }

  } else if (action === 'admin_kpis') {
    let utentiAttivi=0;
    try {
      const d = await notionReq('POST','/databases/'+DBS.utenti+'/query',{filter:{or:[{property:'Attivo',checkbox:{equals:true}},{property:'Status',status:{equals:'Attivo'}},{property:'Stato',status:{equals:'Attivo'}}]},page_size:100});
      utentiAttivi = (d.results||[]).length;
    } catch {}
    let eventiProssimi=0;
    try {
      const today = new Date().toISOString().split('T')[0];
      const d = await notionReq('POST','/databases/'+DBS.eventi+'/query',{filter:{or:[{property:'Data',date:{on_or_after:today}},{property:'Date',date:{on_or_after:today}}]},page_size:100});
      eventiProssimi = (d.results||[]).length;
    } catch {}
    const c = await Promise.all([qCount(DBS.utenti),qCount(DBS.orders),qCount(DBS.corsi),qCount(DBS.waitlist)]);
    result = {utentiTotali:c[0],utentiAttivi,ordiniTotale:c[1],corsiAttivi:c[2],eventiProssimi,waitlistIscritti:c[3],timestamp:new Date().toISOString()};

  } else if (action === 'gestionale_kpis') {
    const c = await Promise.all([qCount(DBS.fatture),qCount(DBS.conti),qCount(DBS.dipendenti),qCount(DBS.magazzino),qCount(DBS.documenti),qCount(DBS.campagne)]);
    result = {fattureTotali:c[0],contiTotali:c[1],dipendentiTotali:c[2],magazzinoArticoli:c[3],documentiTotali:c[4],campagneTotali:c[5],timestamp:new Date().toISOString()};

  } else if (action === 'activity_feed') {
    const lim = body.limit||20;
    const fDbs = [{id:DBS.utenti,type:'user',label:'Utenti'},{id:DBS.orders,type:'order',label:'Ordini'},{id:DBS.waitlist,type:'system',label:'Waitlist'},{id:DBS.eventi,type:'event',label:'Eventi'},{id:DBS.corsi,type:'course',label:'Corsi'}];
    async function rp(id,type,label) {
      try {
        const d = await notionReq('POST','/databases/'+id+'/query',{sorts:[{timestamp:'last_edited_time',direction:'descending'}],page_size:5});
        return (d.results||[]).map(p=>{ const tp=Object.values(p.properties||{}).find(pr=>pr.type==='title'); return {id:p.id,type,title:label+': '+((tp&&tp.title)?tp.title.map(t=>t.plain_text).join(''):'Senza nome'),description:'Modificato',timestamp:p.last_edited_time,date:p.last_edited_time}; });
      } catch { return []; }
    }
    const all = await Promise.all(fDbs.map(db=>rp(db.id,db.type,db.label)));
    result = {items:[].concat.apply([],all).sort((a,b)=>new Date(b.timestamp)-new Date(a.timestamp)).slice(0,lim)};

  } else if (action === 'ping') {
    result = {status:'ok',notion:true,timestamp:new Date().toISOString()};

  } else {
    result = {success:false,error:'Azione non riconosciuta: '+action};
  }
} catch (error) {
  result = {success:false,action,error:error.message};
}

return [{json:result}];
